extern "C" __global__ __aicore__ void pointnet2_gather_points(GM_ADDR points, GM_ADDR idx, GM_ADDR out, GM_ADDR workspace, GM_ADDR tiling) {
    GET_TILING_DATA(t, tiling);
    for (uint32_t bb = 0; bb < t.b; ++bb) {
        for (uint32_t cc = 0; cc < t.c; ++cc) {
            for (uint32_t mm = 0; mm < t.m; ++mm) {
                int32_t src = ((__gm__ int32_t*)idx)[bb * t.m + mm];
                ((__gm__ float*)out)[bb * t.c * t.m + cc * t.m + mm] = ((__gm__ float*)points)[bb * t.c * t.n + cc * t.n + src];
            }
        }
    }
}

